import{_ as a,o as e,c as r,S as d}from"./chunks/framework.C6RQlTYc.js";const u=JSON.parse('{"title":"向量数据库","description":"","frontmatter":{},"headers":[],"relativePath":"直击概念/17ai/s_ai_26-vector_database.md","filePath":"直击概念/17ai/s_ai_26-vector_database.md","lastUpdated":1778207238000}'),i={name:"直击概念/17ai/s_ai_26-vector_database.md"};function s(o,t,n,l,h,c){return e(),r("div",null,[...t[0]||(t[0]=[d(`<h1 id="向量数据库" tabindex="-1">向量数据库 <a class="header-anchor" href="#向量数据库" aria-label="Permalink to &quot;向量数据库&quot;">​</a></h1><h2 id="概念" tabindex="-1">概念 <a class="header-anchor" href="#概念" aria-label="Permalink to &quot;概念&quot;">​</a></h2><p>向量数据库（Vector Database）是一种专门存储和检索<strong>高维向量</strong>的数据库系统。与传统数据库按精确值查询不同，向量数据库通过<strong>计算向量之间的相似度</strong>来找到最相关的结果。</p><p>在 AI 应用中，向量数据库是 RAG、语义搜索、推荐系统等功能的<strong>核心基础设施</strong>。</p><h2 id="为什么需要向量数据库" tabindex="-1">为什么需要向量数据库 <a class="header-anchor" href="#为什么需要向量数据库" aria-label="Permalink to &quot;为什么需要向量数据库&quot;">​</a></h2><p>传统关键词搜索的问题：</p><ul><li><code>&quot;JavaScript 异步编程&quot;</code> 搜不到 <code>&quot;JS async/await 详解&quot;</code></li><li>用户说 <code>&quot;便宜好用的手机&quot;</code> 搜不到 <code>&quot;高性价比智能机推荐&quot;</code></li></ul><p>向量搜索用语义相似度替代关键词匹配，理解了用户的<strong>意图</strong>而非文字。</p><h2 id="核心概念" tabindex="-1">核心概念 <a class="header-anchor" href="#核心概念" aria-label="Permalink to &quot;核心概念&quot;">​</a></h2><h3 id="向量索引-vector-index" tabindex="-1">向量索引（Vector Index） <a class="header-anchor" href="#向量索引-vector-index" aria-label="Permalink to &quot;向量索引（Vector Index）&quot;">​</a></h3><p>为加速海量向量间的相似度搜索而设计的数据结构：</p><ul><li><strong>ANN（近似最近邻）</strong>：牺牲微小精度换取极大加速</li><li><strong>HNSW（分层可导航小世界图）</strong>：当前最主流的 ANN 算法</li><li><strong>IVF（倒排文件索引）</strong>：先聚类再在最近的几个簇中搜索</li></ul><h3 id="相似度度量" tabindex="-1">相似度度量 <a class="header-anchor" href="#相似度度量" aria-label="Permalink to &quot;相似度度量&quot;">​</a></h3><table><thead><tr><th>方法</th><th>描述</th><th>适用场景</th></tr></thead><tbody><tr><td>余弦相似度</td><td>angle between vectors</td><td>语义搜索（最常用）</td></tr><tr><td>欧氏距离</td><td>straight-line distance</td><td>图像、音频</td></tr><tr><td>点积（Dot Product）</td><td>vector multiplication</td><td>需要关注向量大小的场景</td></tr></tbody></table><h3 id="metadata-过滤" tabindex="-1">Metadata 过滤 <a class="header-anchor" href="#metadata-过滤" aria-label="Permalink to &quot;Metadata 过滤&quot;">​</a></h3><p>在向量相似度之外，结合传统字段过滤：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0"><code><span class="line"><span>&quot;在 2024 年发表的论文中，找到与&#39;Transformer 架构&#39;最相关的...&quot;</span></span>
<span class="line"><span>        ↑ metadata 过滤                    ↑ 向量相似度</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h2 id="主流向量数据库" tabindex="-1">主流向量数据库 <a class="header-anchor" href="#主流向量数据库" aria-label="Permalink to &quot;主流向量数据库&quot;">​</a></h2><table><thead><tr><th>名称</th><th>类型</th><th>特点</th></tr></thead><tbody><tr><td><strong>Milvus</strong></td><td>专用向量库</td><td>开源、分布式、高性能</td></tr><tr><td><strong>Pinecone</strong></td><td>云服务</td><td>全托管、零运维</td></tr><tr><td><strong>Weaviate</strong></td><td>专用向量库</td><td>开源、内置向量化</td></tr><tr><td><strong>Qdrant</strong></td><td>专用向量库</td><td>Rust 编写、高性能</td></tr><tr><td><strong>Chroma</strong></td><td>轻量向量库</td><td>适合原型和小项目</td></tr><tr><td><strong>pgvector</strong></td><td>PostgreSQL 插件</td><td>在现有 PG 中直接用</td></tr><tr><td><strong>Elasticsearch</strong></td><td>搜索引擎+向量</td><td>全文搜索+向量搜索一体</td></tr><tr><td><strong>FAISS</strong></td><td>向量索引库</td><td>Meta 开源，纯向量索引</td></tr><tr><td><strong>Voy</strong></td><td>向量索引</td><td>Spotify 开源，WASM 可运行</td></tr></tbody></table><h2 id="前端使用场景" tabindex="-1">前端使用场景 <a class="header-anchor" href="#前端使用场景" aria-label="Permalink to &quot;前端使用场景&quot;">​</a></h2><h3 id="浏览器端向量搜索" tabindex="-1">浏览器端向量搜索 <a class="header-anchor" href="#浏览器端向量搜索" aria-label="Permalink to &quot;浏览器端向量搜索&quot;">​</a></h3><ul><li><strong>Transformers.js</strong> + <strong>Voy</strong>：在浏览器中做 Embedding + 向量检索</li><li>适合离线 PWA 应用、客户端隐私数据搜索</li></ul><h3 id="后端向量数据库-前端-api" tabindex="-1">后端向量数据库 + 前端 API <a class="header-anchor" href="#后端向量数据库-前端-api" aria-label="Permalink to &quot;后端向量数据库 + 前端 API&quot;">​</a></h3><p>最常见的架构：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0"><code><span class="line"><span>用户输入 → 后端 API → Embedding → 向量库检索 → Top-K 文档 → 返回前端</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>前端只负责展示，不需要处理向量计算。</p><h2 id="面试常问" tabindex="-1">面试常问 <a class="header-anchor" href="#面试常问" aria-label="Permalink to &quot;面试常问&quot;">​</a></h2><ul><li>向量数据库和传统数据库的核心区别是什么？</li><li>为什么向量搜索不追求精确匹配，而用近似最近邻（ANN）？</li><li>列举一个前端可以用的向量检索方案。</li></ul><h2 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-label="Permalink to &quot;参考&quot;">​</a></h2><ul><li><a href="https://milvus.io/docs" target="_blank" rel="noreferrer">Milvus Documentation</a></li><li><a href="https://www.pinecone.io/learn/vector-database/" target="_blank" rel="noreferrer">Pinecone: What is a Vector Database</a></li><li><a href="https://github.com/spotify/voy" target="_blank" rel="noreferrer">Voy: WASM vector similarity search</a></li></ul>`,30)])])}const b=a(i,[["render",s]]);export{u as __pageData,b as default};
